INSERT INTO "chat_states" VALUES(1,'{"chats": [{"id": "a4546ab2-dab7-4d62-b5ba-c74a4f5e9ee4", "title": "snapap", "archived": false, "pinned": false, "tags": [], "folderId": null, "chatLanguage": "en", "chatLanguageHint": "snapap", "createdAt": "2026-03-02T05:22:20.200Z", "updatedAt": "2026-03-02T05:22:35.374Z", "messages": [{"id": "40720e08-194a-406b-84e7-2cde4e84ff2b", "role": "user", "content": "snapap", "createdAt": "2026-03-02T05:22:21.797Z", "provider": "", "sources": [], "traceLines": [], "streaming": false, "error": false}, {"id": "6cd2ab71-271f-489a-88a8-73f4ba5507f9", "role": "assistant", "content": "На основе контекста документа **ACRONIS DATA**, команда `snapap` не упоминается. Однако, в контексте установки агента Acronis для cPanel/WHM присутствуют команды для работы с модулем ядра `snapapi26`.\n\nВот соответствующие команды из документа:\n\n1.  **Установка пакета модуля:**\n    ```bash\n    yum install snapapi26_modules.noarch\n    ```\n\n2.  **Проверка установки пакета:**\n    ```bash\n    rpm -q snapapi26_modules\n    ```\n\n3.  **Установка модуля в DKMS:**\n    ```bash\n    dkms install -m snapapi26 -v 0.8.58\n    ```\n\n4.  **Проверка загруженного модуля в ядро:**\n    ```bash\n    lsmod | grep snapapi26\n    ```\n\n5.  **Обновление зависимостей модулей и загрузка:**\n    ```bash\n    depmod -a $(uname -r)\n    modprobe -v snapapi26\n    ```\n\n**Источник:** [ACRONIS DATA](https://wiki.netwize.work/doc/acronis-data-ClTZYmdh4z)", "createdAt": "2026-03-02T05:22:21.798Z", "provider": "deepseek", "sources": [{"document_id": "c6cff6fb-fda7-491b-b84e-a100e6ee2cd4", "title": "ACRONIS DATA", "url": "https://wiki.netwize.work/doc/acronis-data-ClTZYmdh4z", "score": 0.8568344709277153, "excerpt": "Agent через WHM используя логин и пароль\n\nyum install snapapi26_modules.noarch\n\nrpm -q snapapi26_modules\n\ndkms install -m snapapi26 -v 0.8.58\n\nlsmod | grep snapapi26\ndepmod -a $(uname -r)\nmodprobe -v snapapi26"}], "traceLines": ["• Custom prompt: on", "• Collecting relevant context...", "• Найдено источников: 1", "• Генерирую ответ...", "• Провайдер: deepseek"], "streaming": false, "error": false}]}, {"id": "fb4e895a-240a-40f3-b5c2-265822a1939e", "title": "cPanel Update", "archived": false, "pinned": false, "tags": [], "folderId": "45b5b1ee-5431-4ac9-b3d9-1d7b1075c4b0", "chatLanguage": "en", "chatLanguageHint": "[[cPanel Update]]", "createdAt": "2026-03-01T07:52:18.989Z", "updatedAt": "2026-03-02T05:39:05.286Z", "messages": [{"id": "43dd3ccd-237f-4699-a3b2-3955725df735", "role": "user", "content": "[[cPanel Update]]", "createdAt": "2026-03-01T07:52:47.619Z", "provider": "", "sources": [], "traceLines": [], "streaming": false, "error": false}, {"id": "1c51bab8-72b9-46fa-b70d-4f13440e8c08", "role": "assistant", "content": "На основе документации, процесс обновления cPanel включает следующие шаги:\n\n### 1. Настройка директории для обновления\nПеред запуском обновления необходимо настроить `STAGING_DIR` в конфигурационном файле, указав раздел с наибольшим свободным местом (обычно `/home`). Это делается с помощью WHM API:\n```bash\nwhmapi1 update_updateconf STAGING_DIR=$(df -h | grep home | sort -nk4 | tail -n 1| awk ''{print $6}'') CPANEL=132.0.25\n```\n*   `CPANEL=132.0.25` — целевая версия для обновления (укажите актуальную версию).\n\n### 2. Проверка и защита конфигурации\nПроверьте созданный конфигурационный файл и установите на него immutable-бит, чтобы предотвратить его изменение во время процесса обновления (например, со стороны Salt):\n```bash\ncat /etc/cpupdate.conf\nchattr +i /etc/cpupdate.conf\n```\n\n### 3. Запуск обновления\nЗапустите стандартный скрипт обновления cPanel:\n```bash\n/scripts/upcp\n```\n\n### 4. Завершение процесса\nПосле успешного завершения обновления **снимите immutable-бит** с конфигурационного файла:\n```bash\nchattr -i /etc/cpupdate.conf\n```\n\n### Важное замечание из документации\nПри обновлении серверов WordPress (например, с релиза 94 на 102) может возникнуть проблема, если установлена служба `nscd`. В этом случае перед обновлением необходимо выполнить:\n```bash\nsystemctl stop nscd\n```\n\n**Источники:**\n*   Основные шаги обновления: [cPanel Update](https://wiki.netwize.work/doc/cpanel-update-vKpN0XU0gg)\n*   Проблема с `nscd`: [cPanel server update](https://wiki.netwize.work/doc/cpanel-server-update-hWNhWkdDFK)", "createdAt": "2026-03-01T07:52:47.619Z", "provider": "deepseek", "sources": [{"document_id": "b697583a-cc44-4049-9706-67fb21f65f47", "title": "cPanel Update", "url": "https://wiki.netwize.work/doc/cpanel-update-vKpN0XU0gg", "score": 1.0696924102306364, "excerpt": "Update cPanel\n/\n\nwhmapi1 update_updateconf STAGING_DIR=$(df -h | grep home | sort -nk4 | tail -n 1| awk ''{print $6}'') CPANEL=132.0.25\n\ncat /etc/cpupdate.conf ; chattr +i /etc/cpupdate.conf\n/scripts/upcp && chattr -i"}, {"document_id": "f9493e5a-f987-4394-8726-eadc2d0560c8", "title": "cPanel server update", "url": "https://wiki.netwize.work/doc/cpanel-server-update-hWNhWkdDFK", "score": 1.068758614063263, "excerpt": "cPanel server update\nНевозможно предоставить {include} Включенная страница не может быть найдена.\nIssue when Update wordpress servers to release 102. from 94.\nIf nscd installed, need run \"systemctl stop nscd\".\nIf nscd not"}, {"document_id": "eafa4e48-7b74-435d-aa18-25d24c87fd18", "title": "How-to update cPanel_WHM on cpanel_wordpress serve", "url": "https://wiki.netwize.work/doc/how-to-update-cpanel_whm-on-cpanel_wordpress-serve-dnvcE9J68H", "score": 1.0699551624059678, "excerpt": "int $6}'') CPANEL=11.94.0.23\nSet immutable bit for file /etc/cpupdate.conf to prevent salt to change settings of the staging directory, during cpanel update.\nchattr +i /etc/cpupdate.conf\nRun update process. During the"}, {"document_id": "77430a23-e2b2-44b3-98d9-bbf8afcc3adc", "title": "The cpanel.config File", "url": "https://wiki.netwize.work/doc/the-cpanelconfig-file-LfMugK1jzS", "score": 1.0699999999999998, "excerpt": "The cpanel.config File\nOverview\nThe /var/cpanel/cpanel.config file stores all of the settings that exist in WHM''s Tweak Settings interface (WHM >> Home >> Server Configuration >> Tweak Settings). For more information about the"}, {"document_id": "bf58d509-0d92-4901-a01b-b95ed0f21045", "title": "cPanel software parameters", "url": "https://wiki.netwize.work/doc/cpanel-software-parameters-qrWpnH24za", "score": 1.0699999999999998, "excerpt": "cPanel software parameters\nThis article describe cPanel software configuration for WordPress hosting servers.\nUsed software\nWeb server\nNginx server – front end HTTP/HTTPS server. Nginx proxy HTTP/HTTPS for PHP scripts to the Apache"}, {"document_id": "b2339b36-45e9-40db-90b0-cbaf956dc25d", "title": "cPanel software parameters (1)", "url": "https://wiki.netwize.work/doc/cpanel-software-parameters-1-QHwceATdaI", "score": 1.0699999999999998, "excerpt": "cPanel software parameters\nThis article describe cPanel software configuration for WordPress hosting servers.\nUsed software\nWeb server\nNginx server – front end HTTP/HTTPS server. Nginx proxy HTTP/HTTPS for PHP scripts to the Apache"}, {"document_id": "811039ca-1827-49fd-ae76-84ddd5f0df67", "title": "How find cPanel user which made requests to the external services (ftp,http,https) CPANELABUSE", "url": "https://wiki.netwize.work/doc/how-find-cpanel-user-which-made-requests-to-the-external-services-ftphttphttps-cpanelabuse-685IXGcRwn", "score": 1.0699999999999998, "excerpt": "How find cPanel user which made requests to the external services (ftp,http,https) CPANELABUSE\nPeriodically we receive from third party hosting abuses that some our customer perform attack to external website.\nThis document describe how"}, {"document_id": "6de56eb6-552d-4981-bfa5-9874c3aab996", "title": "cPanel API", "url": "https://wiki.netwize.work/doc/cpanel-api-C1dgXnCaEP", "score": 1.043763257265091, "excerpt": "cpgreylist_list_entries_for_common_mail_provider provider=cpanel provider-0=dpanel\ncpgreylist_load_common_mail_providers_config\ncpgreylist_save_common_mail_providers_config google=0 yahoo=0\ncpgreylist_status"}, {"document_id": "0845f141-118a-4f5f-939c-1cf380c443be", "title": "Update the SSL dreamwp.com wildcard certificate", "url": "https://wiki.netwize.work/doc/update-the-ssl-dreamwpcom-wildcard-certificate-RHXWx0U0jE", "score": 1.0139560770988465, "excerpt": "Update the SSL dreamwp.com wildcard certificate\nCurrently, all WordPress production servers are managed centrally by Salt and have installed wildcard SSL certificate for the domain dreamwp.com\nBut the \"validity before\" date is coming soon and"}, {"document_id": "c1af81ee-84bd-4988-97db-3e164ddd9f8b", "title": "Generate CSR file for customer''s website on cPanel", "url": "https://wiki.netwize.work/doc/generate-csr-file-for-customers-website-on-cpanel-X7ipCoix90", "score": 1.0088162642717362, "excerpt": "Generate CSR file for customer''s website on cPanel server from CRMS\nStep-by-step guide\nOpen CRMS\nif you need install certificate for Europe or USA server please use CRMS in Europe location - https://www.secureapi.eu/crms/home/login/\nFind"}, {"document_id": "2e1ba449-c7b2-4e19-ace6-29f54f178828", "title": "crazidomain-files", "url": "https://wiki.netwize.work/doc/crazidomain-files-c2fPvZczAC", "score": 14.1039428710938, "excerpt": "[cpanel/wordpress/hooks/Nginx-Helper-Scripts/ChangeMXCheck.conf](https://google.com)\n\ncpanel/wordpress/hooks/Nginx-Helper-Scripts/InstallSSL.conf\n\ncpanel/wordpress/hooks/Nginx-Helper-Scripts/NginxReload.conf\n\ncpanel/wordpress/hooks/WordPress/nginx-vhost_ipv6.tt\n\ncpanel/wordpress/"}], "traceLines": ["• Custom prompt: on", "• Collecting relevant context...", "• Найдено источников: 11", "• Генерирую ответ...", "• Провайдер: deepseek"], "streaming": false, "error": false}, {"id": "4fc0a605-9d67-4097-b0c7-f9355ef418cf", "role": "user", "content": "[[How find cPanel user which made requests to the external services (ftp,http,https) CPANELABUSE]]", "createdAt": "2026-03-01T16:30:38.310Z", "provider": "", "sources": [], "traceLines": [], "streaming": false, "error": false}, {"id": "882b8f46-a84d-42fa-947b-556debd97ce1", "role": "assistant", "content": "На основе документации, вот пошаговая инструкция по поиску пользователя cPanel, который выполнял запросы к внешним сервисам (FTP, HTTP, HTTPS) при получении жалобы (abuse):\n\n### 1. Получение данных\nВам необходимо иметь **IP-адрес цели атаки** (например, `208.110.72.58`).\n\n### 2. Подключение к серверу логов\nВойдите по SSH на сервер **syslog01.per01.ds.network**. В каталоге `/mnt/log/cpanelabuse` хранятся логи в формате iptables для каждого хоста cPanel с шаблоном имени `<полное_имя_хоста>_abuse.log`.\n\n### 3. Поиск IP-адреса в логах\nИспользуйте команду `grep` для поиска целевого IP-адреса в файлах логов.\n\n**Пример:**\n```bash\n# Перейдите в каталог с логами\ncd /mnt/log/cpanelabuse\n\n# Найдите файлы, содержащие целевой IP\ngrep -lr 208.110.72.58 .\n\n# Пример вывода:\n./wp-cp1.development.au.syrahost.com_abuse.log\n./webcloud44.au.syrahost.com_abuse.log\n\n# Просмотрите конкретные записи в найденном файле\ngrep 208.110.72.58 webcloud44.au.syrahost.com_abuse.log\n```\n**Пример строки лога:**\n```\nSep 30 07:37:01 webcloud44.au.syrahost.com kernel: [1247408.252446] CPANELABUSE IN= OUT=eth0 SRC=103.67.235.74 DST=208.110.72.58 LEN=52 TOS=0x00 PREC=0x00 TTL=64 ID=63188 DF PROTO=TCP SPT=48666 DPT=80 WINDOW=233 RES=0x00 ACK URGP=0 UID=597 GID=593\n```\n**Ключевые поля:**\n*   `DST=208.110.72.58` — целевой IP-адрес.\n*   `DPT=80` — целевой порт (80 = HTTP, 443 = HTTPS, 21 = FTP).\n*   `UID=597` — идентификатор пользователя Linux, от имени которого был выполнен запрос.\n\n### 4. Определение имени пользователя cPanel по UID\nПодключитесь по SSH к исходному хосту (например, `webcloud44.au.syrahost.com`) и выполните:\n```bash\n# Найдите пользователя по UID в /etc/passwd\ngrep -w 597 /etc/passwd\n# Пример вывода: tomsecuy:x:597:593::/home/tomsecuy:/usr/local/cpanel/bin/jailshell\n```\n**Для CloudLinux 7+** можно использовать команду `id`:\n```bash\nid 597\n```\n\n### Итог\nВы определили, что пользователь **tomsecuy** (UID=597) с хоста **webcloud44.au.syrahost.com** отправлял HTTP-запросы (порт 80) на целевой IP-адрес.\n\n**Источник:** [How find cPanel user which made requests to the external services (ftp,http,https) CPANELABUSE](https://wiki.netwize.work/doc/how-find-cpanel-user-which-made-requests-to-the-external-services-ftphttphttps-cpanelabuse-685IXGcRwn)", "createdAt": "2026-03-01T16:30:38.310Z", "provider": "deepseek", "sources": [{"document_id": "811039ca-1827-49fd-ae76-84ddd5f0df67", "title": "How find cPanel user which made requests to the external services (ftp,http,https) CPANELABUSE", "url": "https://wiki.netwize.work/doc/how-find-cpanel-user-which-made-requests-to-the-external-services-ftphttphttps-cpanelabuse-685IXGcRwn", "score": 1.0699999999999998, "excerpt": "How find cPanel user which made requests to the external services (ftp,http,https) CPANELABUSE\nPeriodically we receive from third party hosting abuses that some our customer perform attack"}, {"document_id": "bf58d509-0d92-4901-a01b-b95ed0f21045", "title": "cPanel software parameters", "url": "https://wiki.netwize.work/doc/cpanel-software-parameters-qrWpnH24za", "score": 1.0699999999999998, "excerpt": "cPanel software parameters\nThis article describe cPanel software configuration for WordPress hosting servers.\nUsed software\nWeb server\nNginx server – front end HTTP/HTTPS server. Nginx proxy HTTP/HTTPS for PHP scripts to the Apache"}, {"document_id": "b2339b36-45e9-40db-90b0-cbaf956dc25d", "title": "cPanel software parameters (1)", "url": "https://wiki.netwize.work/doc/cpanel-software-parameters-1-QHwceATdaI", "score": 1.0699999999999998, "excerpt": "cPanel software parameters\nThis article describe cPanel software configuration for WordPress hosting servers.\nUsed software\nWeb server\nNginx server – front end HTTP/HTTPS server. Nginx proxy HTTP/HTTPS for PHP scripts to the Apache"}, {"document_id": "bafe107b-9d06-4fe2-aa75-6b5e165c5be1", "title": "Mitigation inbound HTTP DDoS attacks to customer w", "url": "https://wiki.netwize.work/doc/mitigation-inbound-http-ddos-attacks-to-customer-w-02lUzlbAmu", "score": 0.8389977213740348, "excerpt": "from multiple IP addresses. In this case, the number of requests from each of the IP addresses is limited. This makes it impossible for a ban attackers IPs manually or automatically.\nHow to track and find out about the DDoS attack\nWe have"}, {"document_id": "a7d40440-0b05-4b5a-ac66-6af1885daa30", "title": "How to disable ModSecurity rule for cPanel user", "url": "https://wiki.netwize.work/doc/how-to-disable-modsecurity-rule-for-cpanel-user-TszZn1rkmC", "score": 0.8351981776580214, "excerpt": "need to disable Modsecurity rule.\nFor disabling ModSecurity for HTTPS website\ncreate file /etc/apache2/conf.d/userdata/ssl/2_4/kayeblum/domainsexample.com/modsecurity_disable.conf\nmkdir -p /etc/apache2/conf"}, {"document_id": "0307f175-a6b2-4b5d-95f0-017834545f03", "title": "Fix cPanel account DB map", "url": "https://wiki.netwize.work/doc/fix-cpanel-account-db-map-Nh8fchVXqv", "score": 1.069624788761139, "excerpt": "Fix cPanel account DB map\nCASE 0: User does not exist in the database map\nSymptoms\nChecking\nFix\nCASE 1: Account lost mysql users\nSymptoms: Hosting manager lost mysql users for account\nChecking\nFix\nCASE 2: Mysql users lost privileges for"}, {"document_id": "77430a23-e2b2-44b3-98d9-bbf8afcc3adc", "title": "The cpanel.config File", "url": "https://wiki.netwize.work/doc/the-cpanelconfig-file-LfMugK1jzS", "score": 1.0699999999999998, "excerpt": "The cpanel.config File\nOverview\nThe /var/cpanel/cpanel.config file stores all of the settings that exist in WHM''s Tweak Settings interface (WHM >> Home >> Server Configuration >> Tweak Settings). For more information about the"}, {"document_id": "c1af81ee-84bd-4988-97db-3e164ddd9f8b", "title": "Generate CSR file for customer''s website on cPanel", "url": "https://wiki.netwize.work/doc/generate-csr-file-for-customers-website-on-cpanel-X7ipCoix90", "score": 1.0088162642717362, "excerpt": "Generate CSR file for customer''s website on cPanel server from CRMS\nStep-by-step guide\nOpen CRMS\nif you need install certificate for Europe or USA server please use CRMS in Europe location - https://www.secureapi.eu/crms/home/login/\nFind"}, {"document_id": "dad6a3f2-0b92-4fbf-8ea3-d3ec76772bae", "title": "Transfer Existing Site Error_ A test of the selected domain has failed (HTTP error_ 404)", "url": "https://wiki.netwize.work/doc/transfer-existing-site-error_-a-test-of-the-selected-domain-has-failed-http-error_-404-mptYn4bFZH", "score": 0.8429765586555004, "excerpt": ".chagi1jm.php'' not accessible at https://naq1bz35.dreamwp.com/deleteme.chagi1jm.php''. 2019-07-09 12:07:13.26279900 FAILURE [3; /usr/bin/curl] https://naq1bz35.dreamwp.com/deleteme.chagi1jm.php?n=3&m=4 [http code=404] @103.226.222.34(122"}, {"document_id": "efbc65e1-fc6b-4f41-b153-5fa4c5931c93", "title": "cPanel", "url": "https://wiki.netwize.work/doc/cpanel-dK658pwBUK", "score": 1.069871402978897, "excerpt": "Pages\nDreamscape skin change apply\nChange root password on cPanel and WordPress\nHow to add additional php.ini file for a user inside CageFS\nChange password reseller account\nDuplicate rpm Package - CloudLinux\nHow can we stop"}, {"document_id": "2e1ba449-c7b2-4e19-ace6-29f54f178828", "title": "crazidomain-files", "url": "https://wiki.netwize.work/doc/crazidomain-files-c2fPvZczAC", "score": 14.1039428710938, "excerpt": "[cpanel/wordpress/hooks/Nginx-Helper-Scripts/ChangeMXCheck.conf](https://google.com)\n\ncpanel/wordpress/hooks/Nginx-Helper-Scripts/InstallSSL.conf\n\ncpanel/wordpress/hooks/Nginx-Helper-Scripts/NginxReload.conf\n\ncpanel/wordpress/hooks/WordPress/nginx-vhost_ipv6.tt\n\ncpanel/wordpress/"}], "traceLines": ["• Custom prompt: on", "• Collecting relevant context...", "• Найдено источников: 11", "• Генерирую ответ...", "• Провайдер: deepseek"], "streaming": false, "error": false}, {"id": "49434997-cca4-4ce7-9006-06d0b3982f0e", "role": "user", "content": "где смотреть сам процесс по логам - как смотреть", "createdAt": "2026-03-02T05:39:05.286Z", "provider": "", "sources": [], "traceLines": [], "streaming": false, "error": false}, {"id": "09d8795e-0585-4bc0-9cff-24e0aea57c73", "role": "assistant", "content": "", "createdAt": "2026-03-02T05:39:05.286Z", "provider": "", "sources": [], "traceLines": ["• Custom prompt: on", "• Collecting relevant context..."], "streaming": true, "error": false}]}, {"id": "85a8358d-49fd-4b82-9a02-f5595dae74fb", "title": "ACRONIS DATA", "archived": false, "pinned": false, "tags": [], "folderId": "45b5b1ee-5431-4ac9-b3d9-1d7b1075c4b0", "chatLanguage": "ru", "chatLanguageHint": "[[ACRONIS DATA]] - опиши и дай все информацию", "createdAt": "2026-03-01T07:55:07.266Z", "updatedAt": "2026-03-01T10:17:28.611Z", "messages": [{"id": "7e2c0fc3-c892-4eca-b630-d6e0f1ad04f7", "role": "user", "content": "[[ACRONIS DATA]] - опиши и дай все информацию", "createdAt": "2026-03-01T07:55:26.161Z", "provider": "", "sources": [], "traceLines": [], "streaming": false, "error": false}, {"id": "97c9ce1f-82b9-44ff-ae25-25cd38c21584", "role": "assistant", "content": "На основе документа **ACRONIS DATA** предоставляю полную информацию.\n\n## Общая информация\nДокумент содержит технические данные для работы с Acronis Cyber Protect в инфраструктуре HostPapa. Включает учётные данные, токены, команды установки и настройки агентов резервного копирования.\n\n## Учётные данные и токены\n\n### Основные ключи доступа\n*   **client_id:** `a78a31ad-0fd4-4496-92e4-95a0fc29dd8b`\n*   **client_secret:** `w5su57syyk7nyi6rg3v7adqcfqmovd64zqyvfgoyhma6xqb7l6d4`\n\n### Токены установки агентов (Install Tokens)\n*   **Общий токен (YYZ2):** `1C0C-964D-4515`\n*   **Токен для дата-центра DUB1:** `7C97-A4F5-44B2`\n*   **Токен для дата-центра MIA1:** `9073-6AD9-43F7`\n\n### Учётные записи для регистрации агентов\n*   **Пользователь для YYZ2:**\n    *   Логин: `yyz2backupuser`\n    *   Пароль: `ooghiungudee5Aeteesh7pie5aipae`\n*   **Пользователь для MIA1:**\n    *   Логин: `mia1backupuser`\n    *   Пароль: `lumukuyePoongoh9ohfi`\n*   **Пользователь для LAX2:**\n    *   Логин: `lax2backupuser`\n    *   Пароль: `ain2Cios2Eiw2oB4eiboh6Ochie4ue`\n\n### Прочие секреты из хранилища\n*   **dms_reseller_password:** `d6OZCxfwsY65D2mQNwoNI3LfaA7xDL`\n*   **dms_reseller_token:** `12f11cd8-163f-4ef6-a1ad-775976cbb40e`\n*   **dms_secret_key:** `23d30aaf-2d7a-419b-a2d2-00566022babf`\n*   **imunify360_key:** `IMUNm4TbQJs2pUjlWgm`\n*   **mailchannels_password:** `CMuOB7KTKq7vKxWKM6uNyt2m`\n*   **mm_license_key:** `n7UKFXK7WBDxTuug`\n\n## Команды и процедуры\n\n### 1. Установка агента Acronis для cPanel/WHM\n\n**Способ 1: Через скрипт установки**\n```bash\n# Добавить IP-адреса Acronis в CSF/LFD\n/usr/sbin/csf -a 76.74.128.0/24 ''Acronis backups''\n/usr/sbin/csf -a 162.244.7.0/24 ''Acronis backups''\n/usr/sbin/csf -a 204.44.192.13 ''Acronis backups''\n/usr/sbin/csf -a 10.100.68.0/24 ''Acronis backups''\n\n# Скачать и запустить установщик\nwget https://download.acronis.com/ci/cpanel/stable/install_acronis_cpanel.sh\nbash install_acronis_cpanel.sh\n```\nПосле запуска скрипта необходимо зайти в WHM → \"Acronis backups\" и ввести пароль из хранилища секретов для соответствующего региона.\n\n**Способ 2: Ручная установка (устаревший метод)**\n```bash\n# Установка зависимостей ядра\ndnf -y install \"kernel-devel-uname-r == $(uname -r)\" \"kernel-headers-$(uname -r)\" gcc make dkms elfutils-libelf-devel\n\n# Установка модуля snapapi\nyum install snapapi26_modules.noarch\ndkms install -m snapapi26 -v 0.8.58\ndepmod -a $(uname -r)\nmodprobe -v snapapi26\n```\n\n### 2. Регистрация агента в облаке Acronis\n```bash\n# Общий синтаксис\n/usr/lib/Acronis/RegisterAgentTool/RegisterAgent -t cloud -o register -a https://us5-cloud.acronis.com/ -u <username> -p <password> --token <install_token>\n\n# Пример для MIA1\n/usr/lib/Acronis/RegisterAgentTool/RegisterAgent -t cloud -o register -a https://us5-cloud.acronis.com/ -u mia1backupuser -p lumukuyePoongoh9ohfi --token 9073-6AD9-43F7\n\n# Пример для YYZ2\n/usr/lib/Acronis/RegisterAgentTool/RegisterAgent -t cloud -o register -a https://us5-cloud.acronis.com/ -u yyz2backupuser -p ooghiungudee5Aeteesh7pie5aipae --token 5DA2-A0BC-4C4E\n```\n\n### 3. Установка агента для Linux (не cPanel)\n```bash\n./Cyber_Protection_Agent_for_Linux_x86_64.bin -a -i BackupAndRecoveryAgent -C https://us5-cloud.acronis.com --token=1C0C-964D-4515\n```\n\n### 4. Полная деинсталляция агента Acronis\n```bash\n# Выполнить деинсталлятор\n/usr/lib/Acronis/BackupAndRecovery/uninstall/uninstall -a\n\n# Удалить пакеты\nrpm -e acronis-backup-cpanel\n\n# Очистить оставшиеся файлы\nrm -rf /usr/lib/Acronis/ /var/lib/Acronis/ /etc/Acronis\nrm -rf /usr/local/cpanel/base/3rdparty/acronisbackup\n```\n\n## Важные замечания\n1.  **Облачный портал:** `https://us5-cloud.acronis.com/`\n2.  **Пароли и токены** хранятся в HashiCorp Vault по пути: `hostpapa/kv/list/infra/acronis_cyberinfra/`\n3.  **После установки** необходимо:\n    *   Включить резервное копирование в интерфейсе WHM\n    *   Настроить план защиты, ограничив хранение 14 копий (вместо значения по умолчанию)\n    *   При необходимости отключить резервное копирование для конечных пользователей и реселлеров во время установки\n\n**Источник:** [ACRONIS DATA](https://wiki.netwize.work/doc/acronis-data-ClTZYmdh4z)", "createdAt": "2026-03-01T07:55:26.162Z", "provider": "deepseek", "sources": [{"document_id": "c6cff6fb-fda7-491b-b84e-a100e6ee2cd4", "title": "ACRONIS DATA", "url": "https://wiki.netwize.work/doc/acronis-data-ClTZYmdh4z", "score": 1.0691540163755417, "excerpt": "https://ayatec.eu/introducing-relay-module-hw-622/\nclient_id: a78a31ad-0fd4-4496-92e4-95a0fc29dd8b client_secret: w5su57syyk7nyi6rg3v7adqcfqmovd64zqyvfgoyhma6xqb7l6d4"}, {"document_id": "80121da0-30ed-4061-9189-82c68ecf92aa", "title": "How recover website after WordPress Hosting suspen", "url": "https://wiki.netwize.work/doc/how-recover-website-after-wordpress-hosting-suspen-2aJEyfugxh", "score": 0.8639004376530647, "excerpt": "we see in archive logs:\n[2019-02-12 03:07:57 +0800] info [park] data: {\"domain\":\"newtyres.co.nz\",\"parent_domain\":\"newtyres.co.nz.w5205370.users.internal\",\"user\":\"w5205370\"}\n[2019-02-12 03:07:57 +0800] info [park] data: {\"domain\":"}, {"document_id": "6af46da0-4ec0-4b2b-bd10-b67f4bd7d915", "title": "Migrate from H-Sphere to Plesk for Linux", "url": "https://wiki.netwize.work/doc/migrate-from-h-sphere-to-plesk-for-linux-KAXNHnjp3j", "score": 0.8578645732998847, "excerpt": "session-dir - catalog on source server where migrate session data will be stored; hosting-description - location of hosting-description. yaml file for source server; description-format - format of hosting-description file ( yaml in our case);"}, {"document_id": "632f836e-462e-4a0a-b9f6-afc1ee9aee61", "title": "Decommission cPanel server", "url": "https://wiki.netwize.work/doc/decommission-cpanel-server-UeH6pmZsY4", "score": 0.850396355316043, "excerpt": "Devs.\ndeactivate the server in the hosting API and clear server data\nCreate sub-task to Monitoring team to remove server from Monitoring\nCreate sub-task to backup team to remove server from Backup jobs.\nCreate sub-task to Network storage team"}, {"document_id": "e0d58bf9-2298-4d08-bb7f-34bc4bb26429", "title": "Deploying a New Shared Reseller Host on VHI Using ", "url": "https://wiki.netwize.work/doc/deploying-a-new-shared-reseller-host-on-vhi-using-6jLa0yslVG", "score": 0.8434016627073287, "excerpt": "Contents:\nCreate Virtual Machine\nLicenses\nDNS\nAnsible\nAcronis\nUbersmith\nAdd root Password to Vault\nDisable Automatic Agentless Backup in Acronis\nInventory\nLaunchpad\nAdd Server To Queue\nAdditional information\nChecklist\n1. Create Virtual"}, {"document_id": "f36087cf-ae19-4996-a3a9-d5ae2b4ba4eb", "title": "NMON Collector", "url": "https://wiki.netwize.work/doc/nmon-collector-4OWtgwLQin", "score": 0.8406864085048437, "excerpt": "The directory to store the nmon data files\n\nNMONDIR=\"/var/log/nmon\"\n\n## Default options for nmon\n\nOPTIONS=\"-f -s30 -c2880 -t\"\n\n### Number of days to keep nmon data files\n\nKEEPDAYS=\"31\"\nExpllain options:\nOPTIONS=\"-f -s30 -c2880 -t\"\nf"}, {"document_id": "05baeb78-29a4-4be2-af2b-223bfdbcfe2a", "title": "DeepSearch", "url": "https://wiki.netwize.work/doc/deepsearch-4v4SfqMzmd", "score": 0.8389977213740348, "excerpt": "Степновым, керівником центру розробки великих даних (Big Data) у компанії МТС Діжиталь. Вона присвячена підбору корисних інструментів для роботи з моделями природної мови (LLM), зокрема вільних програмних засобів із веб-інтерфейсом.\nДжерела:"}, {"document_id": "148dfb85-9c5e-434c-9f45-e0f31c1b8f0f", "title": "Kids Documents", "url": "https://wiki.netwize.work/doc/kids-documents-n4bf7iYfZT", "score": 0.8351981776580214, "excerpt": "Приложение полностью локальное.\nФайлы хранятся в:\n/Android/data/com.package.secure/files/\nЗащита:\nAES-256 для фото документов (опционально)\nдоступ только после биометрии\nнельзя сделать скриншот (опциональная фича — Android FLAG_SECURE)\n5. 🧩"}, {"document_id": "a72607f3-4d3a-4d83-93e5-8fc35ed0374c", "title": "SLZB-MR3", "url": "https://wiki.netwize.work/doc/slzb-mr3-UFTEYYgevq", "score": 0.8351981776580214, "excerpt": "после перепрошивки:\n# TH01 CHT8310: Wake -> Calib -> Read calib data -> Selective publish -> (optional) Work 1 min -> Sleep\n# MQTT: publish only non-zero/valid temp/hum/batt + system\n\n# ---------------------------\n# Drivers\nstartDriver"}, {"document_id": "aa7d1d1d-de78-4c40-9e55-8ab219fc6e33", "title": "single lines", "url": "https://wiki.netwize.work/doc/single-lines-if48OMNtwm", "score": 0.8351981776580214, "excerpt": ",//s/^/#/\" \"/home/$i/public_html/.htaccess\"\ndone\n\nAcronis\n./Cyber_Protection_Agent_for_Linux_x86_64.bin -a -i BackupAndRecoveryAgent -C https://us5-cloud.acronis.com --token=1C0C-964D-4515\n\nRsync BIN per-sync  Copy \nrsync"}, {"document_id": "ded15e22-ccea-4205-ab89-cf7bfe298efc", "title": "Error_ A database query has failed Is the entered ", "url": "https://wiki.netwize.work/doc/error_-a-database-query-has-failed-is-the-entered-tyh1IIek5T", "score": 0.703736126422882, "excerpt": "# Error: A database query has failed. Is the entered database information correct? Does the account have available disk space?\n\nWhen we have access to MySQL from a user with credentials (console only), but from ''Installatron'' there is no access with user credentials to MySQL ( on"}], "traceLines": ["• Custom prompt: on", "• Ищу релевантные материалы...", "• Найдено источников: 11", "• Генерирую ответ...", "• Провайдер: deepseek"], "streaming": false, "error": false}]}], "folders": [{"id": "45b5b1ee-5431-4ac9-b3d9-1d7b1075c4b0", "name": "Work", "createdAt": "2026-03-01T07:55:38.892Z", "updatedAt": "2026-03-01T07:55:38.892Z"}], "activeChatId": "fb4e895a-240a-40f3-b5c2-265822a1939e", "ui": {"expandedChats": {"1772267479508-e241f19f88871": true, "b8f3bebb-a7a2-4fff-a122-2c4b019b5f0d": true, "1772267228072-c931432cceed": true, "4c7f07fc-0392-4e17-90de-867791c99fe0": true, "1772260665835-327ff1ec8a601": true, "1772289395427-3fba38b2dc083": true, "c9442ace-abc6-40c9-880b-35d699fd0f54": true, "d81a9892-ec4f-4f55-8b07-844577c38da1": true, "f7672770-e414-448a-9038-081e47a2895c": true, "9dc6ba93-f3d1-400a-8787-44b2736f556f": true, "9974f724-39ad-459f-a06f-ed5e273e8d74": true, "4f569ee6-9fa4-49ac-b37c-056fe681b370": true, "b4a2f8a7-acb4-43a9-ae69-39beaa0b3070": true, "83375756-280e-4ecd-a2b1-d61bf2502977": true, "1259fc69-7f3e-4983-8431-26e671ca1e2e": true, "868d35cf-6a6d-464c-a379-890e1a9f87c9": true, "2e3b7edf-eecd-4671-81f1-0a39eae815dc": true, "a4546ab2-dab7-4d62-b5ba-c74a4f5e9ee4": true, "fb4e895a-240a-40f3-b5c2-265822a1939e": true}, "expandedFolders": {"1772267409165-dabe05305581c": true, "2d6ae3c9-3e9a-4627-8bf7-55c3ff3e974c": true, "__none": true, "45b5b1ee-5431-4ac9-b3d9-1d7b1075c